/* Suggested markup: <div class="uiwiki-stacked-node-counter" tabindex="0"><span>Stacked Node Counter</span></div> */
.uiwiki-stacked-node-counter {
  display: grid;
  place-items: center;
  min-height: 11rem;
  padding: 1.25rem;
  border: 1px solid #ececee;
  border-radius: 22px;
  background: #ffffff;
  color: #111111;
  font: 700 1rem/1.2 Inter, system-ui, sans-serif;
  box-shadow: 0 2px 16px rgba(0, 0, 0, 0.04);
  transition: transform 240ms cubic-bezier(.22, 1, .36, 1), box-shadow 240ms ease;
}
.uiwiki-stacked-node-counter > span {
  padding: .75rem 1rem;
  border-radius: 999px;
  background: #ff9950;
  animation: stacked_node_counter 1.8s ease-in-out infinite alternate;
}
.uiwiki-stacked-node-counter:hover,
.uiwiki-stacked-node-counter:focus-visible {
  transform: translateY(-3px);
  box-shadow: 0 10px 28px rgba(0, 0, 0, 0.08);
}
@keyframes stacked_node_counter {
  from { transform: translateY(0) scale(1); }
  to { transform: translateY(-4px) scale(1.025); }
}
@media (prefers-reduced-motion: reduce) {
  .uiwiki-stacked-node-counter, .uiwiki-stacked-node-counter > span { animation: none; transition: none; }
}
